import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Cross-Repository Change","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/playbooks/cross-repository-change.md","filePath":"projects/arti/playbooks/cross-repository-change.md"}'),o={name:"projects/arti/playbooks/cross-repository-change.md"};function s(t,a,n,p,h,c){return i(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="cross-repository-change" tabindex="-1">Cross-Repository Change <a class="header-anchor" href="#cross-repository-change" aria-label="Permalink to &quot;Cross-Repository Change&quot;">​</a></h1><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>一个行为需要修改两个以上仓库</li><li>修改共享枚举、任务、结果或 API 契约</li><li>改动会影响主站、Backend、Poly 或 CLI 的组合</li></ul><h2 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h2><h3 id="_1-定义行为" tabindex="-1">1. 定义行为 <a class="header-anchor" href="#_1-定义行为" aria-label="Permalink to &quot;1. 定义行为&quot;">​</a></h3><p>先写用户可判断的结果：</p><ul><li>什么行为会改变</li><li>什么必须保持不变</li><li>如何证明完成</li></ul><p>不要以“修改四个文件”作为成功标准。</p><h3 id="_2-画影响图" tabindex="-1">2. 画影响图 <a class="header-anchor" href="#_2-画影响图" aria-label="Permalink to &quot;2. 画影响图&quot;">​</a></h3><p>列出：</p><ul><li>Producer</li><li>Contract Owner</li><li>Consumer</li><li>数据库对象</li><li>部署目标</li><li>回滚入口</li></ul><h3 id="_3-选择主篇" tabindex="-1">3. 选择主篇 <a class="header-anchor" href="#_3-选择主篇" aria-label="Permalink to &quot;3. 选择主篇&quot;">​</a></h3><p>按主要决策和改动量选择 RFC 主篇，其余仓库建立姊妹篇。</p><p>主篇负责：</p><ul><li>动机</li><li>共同设计</li><li>权衡</li><li>全局发布顺序</li></ul><p>姊妹篇负责：</p><ul><li>本仓库实施</li><li>本地测试</li><li>本地回滚</li></ul><h3 id="_4-确认真源" tabindex="-1">4. 确认真源 <a class="header-anchor" href="#_4-确认真源" aria-label="Permalink to &quot;4. 确认真源&quot;">​</a></h3><p>对每个共享对象写清：</p><ul><li>当前 Owner</li><li>当前生产定义</li><li>谁只消费</li><li>是否有历史副本</li></ul><p>发现冲突时不要平均两份实现。以生产真身、更新版本和测试证据选定一个。</p><h3 id="_5-设计兼容期" tabindex="-1">5. 设计兼容期 <a class="header-anchor" href="#_5-设计兼容期" aria-label="Permalink to &quot;5. 设计兼容期&quot;">​</a></h3><p>需要时使用：</p><ul><li>先加后删</li><li>双读单写</li><li>双写校验</li><li>Read-side normalize</li><li>Feature flag</li></ul><p>每个临时兼容层必须有退出条件。</p><h3 id="_6-分仓实施" tabindex="-1">6. 分仓实施 <a class="header-anchor" href="#_6-分仓实施" aria-label="Permalink to &quot;6. 分仓实施&quot;">​</a></h3><p>推荐顺序：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>契约与数据层</span></span>
<span class="line"><span>  → 服务端 Producer</span></span>
<span class="line"><span>  → Consumer</span></span>
<span class="line"><span>  → 清理旧路径</span></span></code></pre></div><p>若新 Consumer 可以兼容旧 Producer，可以先发 Consumer。</p><h3 id="_7-验证" tabindex="-1">7. 验证 <a class="header-anchor" href="#_7-验证" aria-label="Permalink to &quot;7. 验证&quot;">​</a></h3><p>至少覆盖：</p><ul><li>每个仓库的本地测试</li><li>契约测试</li><li>一个端到端真实路径</li><li>失败与重试路径</li><li>历史数据兼容</li></ul><h3 id="_8-更新项目记忆" tabindex="-1">8. 更新项目记忆 <a class="header-anchor" href="#_8-更新项目记忆" aria-label="Permalink to &quot;8. 更新项目记忆&quot;">​</a></h3><p>完成后：</p><ul><li>更新双方 RFC 状态和 PR</li><li>更新本 Handbook 契约或决策索引</li><li>删除已经退出的临时兼容说明</li></ul><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><ul><li>[ ] 主篇与姊妹篇互引</li><li>[ ] Owner 明确</li><li>[ ] 发布和回滚顺序明确</li><li>[ ] 各仓测试通过</li><li>[ ] E2E 路径验证</li><li>[ ] 临时兼容层有退出条件</li><li>[ ] Handbook 已更新</li></ul>`,37)])])}const _=l(o,[["render",s]]);export{u as __pageData,_ as default};
